sys_variable_value.value:
(function(outputs, steps, stepResult, assertEqual)
{
	var test = new x_snc_devtools.TestAPI(outputs, steps, stepResult, assertEqual);
	
	test.SetResult(true);
	
	var strCheck = 'f8520bb12b2f76909083fe395e91bf67';
	

	// Adding a script column to the devtools test table
	var grRecord = new GlideRecord('sys_dictionary');
	grRecord.initialize();
	grRecord.name = 'x_snc_devtools_test';
	grRecord.element = 'script_test';
	grRecord.internal_type = 'script';
	grRecord.sys_scope = 'd689f6901bd38450a89720a8ec4bcbfd'; // DevTools
	var strRecordSysId = x_snc_devtools.GlideRecordInsert(grRecord);

	// No field level ACL: that should trigger a finding
	test.TestCase_InstanceScanCheck(strCheck,'sys_dictionary',strRecordSysId,true);

	var grACL = new GlideRecord('sys_security_acl');
	grACL.initialize();
	grACL.name = 'x_snc_devtools_test.script_test';
	grACL.operation = 'write';
	grACL.decision_type = 'deny';
	grACL.active = true;
	grACL.sys_scope = 'd689f6901bd38450a89720a8ec4bcbfd'; // DevTools
	var strAclSysId = x_snc_devtools.GlideRecordInsert(grACL);
	
	// Field level ACL without admin role: that should still trigger a finding
	test.TestCase_InstanceScanCheck(strCheck,'sys_dictionary',strRecordSysId,true);	

	var grRoleAdmin = x_snc_devtools.GetRoleRecord('admin');

	var grAclRole = new GlideRecord('sys_security_acl_role');
	grAclRole.initialize();
	grAclRole.sys_security_acl = grACL.sys_id;
	grAclRole.sys_user_role = grRoleAdmin.sys_id;
	grAclRole.sys_scope = 'd689f6901bd38450a89720a8ec4bcbfd'; // DevTools
	var strAclRoleSysId = x_snc_devtools.GlideRecordInsert(grAclRole);
	
	// Field level ACL with admin role: that should NOT trigger a finding
	test.TestCase_InstanceScanCheck(strCheck,'sys_dictionary',strRecordSysId,false);	
	
	return test.GetResult();
	
})(outputs, steps, stepResult, assertEqual);
